const isDark = await storage.get('dark_mode_state');
if (isDark) {
  const id = await storage.get('dark_mode_css_id');
  if (id) await dom.removeCSS(id);
  await storage.set('dark_mode_state', false);
  spinner.show('Dark mode disabled');
  setTimeout(() => spinner.hide(), 1000);
} else {
  const id = await dom.injectCSS(`
    html { filter: invert(1) hue-rotate(180deg) !important; }
    img, video, iframe, canvas { filter: invert(1) hue-rotate(180deg) !important; }
  `);
  await storage.set('dark_mode_css_id', id);
  await storage.set('dark_mode_state', true);
  spinner.show('Dark mode enabled');
  setTimeout(() => spinner.hide(), 1000);
}
